#!/usr/bin/env node
const platform = require('./platform').name;
const spawn = require('child_process').spawn;
const path = require('path');

const platformPackages = {
    'linux-x64': 'retypeapp-linux-x64',
    'linux-arm64': 'retypeapp-linux-arm64',
    'osx-x64': 'retypeapp-darwin-x64',
    'osx-arm64': 'retypeapp-darwin-arm64',
    'win-x64': 'retypeapp-win-x64',
    'win-x86': 'retypeapp-win-x86'
};
var execPath;
var processHandle;
var args = [];

var verbose = false,
    reading_args = true;
if (process.argv.length > 2) {
    for (var i = 2; i < process.argv.length; i++) {
        var arg = process.argv[i];
        if (arg == "--") {
            reading_args = false;
        } else if (reading_args && process.argv[i] == "--verbose") {
            verbose = true;
        }

        args.push(process.argv[i]);
    }
}

function verboseLog(message) {
    if (verbose) {
        console.log("Node.JS wrapper: " + message);
    }
}

function resolvePlatformWrapper() {
    const packageName = platformPackages[platform];

    if (!packageName) {
        throw new Error("Unsupported Retype package platform: " + platform);
    }

    try {
        return require.resolve(packageName + '/retype.js');
    } catch (error) {
        const message =
            'Retype platform package "' + packageName + '" is not installed.\n' +
            'Try reinstalling the "retypeapp" package for this platform.';

        if (verbose) {
            throw new Error(message + '\n' + error.message);
        }

        console.error(message);
        process.exit(1);
    }
}

function cleanQuit(code) {
    if (!platform.startsWith("win-") && process.stdout.isTTY) {
        verboseLog("resetting terminal cursor key and keypad modes.");
        process.stdout.write("\x1b[?1l\x1b>");
    }

    verboseLog("exiting with status " + code + ".");
    process.exit(code);
}

execPath = resolvePlatformWrapper();
processHandle = spawn(process.execPath, [execPath].concat(args), { stdio: 'inherit' });

// Continue execution on SIGINT; Retype is supposed to handle it.
process.on("SIGINT", () => {});

processHandle.on('exit', (code, signal) => cleanQuit(code));